use std::backtrace::Backtrace;

#[derive(thiserror::Error, Debug)]
enum ServerError {
    #[error("Internal error")]
    Internal {
        source: Box<dyn std::error::Error + Send + Sync>,
        backtrace: Backtrace,
    },
}

